    let mut chain = RecordChain::new();
    chain.push(10, "Record-A", 100.0).unwrap();
    chain.push(20, "Record-B", 200.0).unwrap();
    chain.push(30, "Record-C", 300.0).unwrap();
    chain.push(40, "Record-D", 400.0).unwrap();

    println!("{}", chain);
    println!("Chain integrity: {}", chain.verify_chain());
    println!("Chain length from first: {}", chain.get(0).unwrap().chain_length());

    // Debug output
